157→// ---------------------------------------------------------------------------
158→// RandomStrategy — infinite strategy yielding random type-aware inputs
159→// ---------------------------------------------------------------------------
160→
161→/// Infinite strategy that generates random inputs matching parameter types.
162→///
163→/// Wraps [`generate_random_inputs`] with an owned RNG. Seeded for
164→/// reproducibility or from system entropy.
165→pub struct RandomStrategy {
166→    rng: StdRng,
167→}
168→
169→impl RandomStrategy {
170→    /// Create a new random strategy. If `seed` is `Some`, the RNG is
171→    /// deterministic (useful for reproducible tests). If `None`, seeds
172→    /// from system entropy.
173→    pub fn new(seed: Option<u64>) -> Self {
174→        let rng = match seed {
175→            Some(s) => StdRng::seed_from_u64(s),
176→            None => StdRng::from_os_rng(),
177→        };
178→        Self { rng }
179→    }
180→}
181→
182→impl InputStrategy for RandomStrategy {
183→    fn next(&mut self, ctx: &StrategyContext) -> Option<Vec<Value>> {
184→        Some(generate_random_inputs(
185→            &ctx.params,
186→            &mut self.rng,
187→            Some(&ctx.capabilities),
188→        ))
189→    }
190→
191→    fn name(&self) -> &str {
192→        "random"
193→    }
194→}
