196→// ---------------------------------------------------------------------------
197→// BoundarySeeds — exhaustible strategy yielding type-aware boundary values
198→// ---------------------------------------------------------------------------
199→
200→/// Yields pre-computed boundary-value input vectors using pairwise coverage.
201→///
202→/// For each parameter position, every boundary value for that parameter's type
203→/// is paired with neutral defaults for all other parameters. This caps the
204→/// candidate count at `sum(boundaries_per_type_i)` instead of the cartesian
205→/// product. Delegates to [`generate_boundary_inputs`] for the actual generation.
206→pub struct BoundarySeeds {
207→    candidates: Vec<Vec<Value>>,
208→    cursor: usize,
209→}
210→
211→impl BoundarySeeds {
212→    pub fn new(params: &[ParamInfo]) -> Self {
213→        Self {
214→            candidates: generate_boundary_inputs(params),
215→            cursor: 0,
216→        }
217→    }
218→}
219→
220→impl InputStrategy for BoundarySeeds {
221→    fn next(&mut self, _ctx: &StrategyContext) -> Option<Vec<Value>> {
222→        if self.cursor < self.candidates.len() {
223→            let v = self.candidates[self.cursor].clone();
224→            self.cursor += 1;
225→            Some(v)
226→        } else {
227→            None
228→        }
229→    }
230→
231→    fn name(&self) -> &str {
232→        "boundary"
233→    }
234→
235→    fn estimated_size(&self) -> Option<u64> {
236→        Some(self.candidates.len() as u64)
237→    }
238→}
