 860→pub fn solve_for_new_path(
 861→    constraints: &[SymExpr],
 862→    negate_index: usize,
 863→    solver_timeout_ms: Option<u64>,
 864→    param_infos: &[ParamInfo],
 865→) -> Result<SolveResult, SolverError> {
 866→    if negate_index >= constraints.len() {
 867→        return Err(SolverError::Unsupported(format!(
 868→            "negate_index {negate_index} out of bounds (len={})",
 869→            constraints.len()
 870→        )));
 871→    }
 872→
 873→    // Debug-only: verify constraint param names exist in param_infos when
 874→    // param_infos is non-empty. Unknown params get default Int sort in Z3,
 875→    // which silently produces wrong solutions for String/Bool params.
 876→    #[cfg(debug_assertions)]
 877→    if !param_infos.is_empty() {
 878→        let known: std::collections::HashSet<&str> =
 879→            param_infos.iter().map(|p| p.name.as_str()).collect();
 880→        for constraint in constraints {
 881→            for name in crate::sym_expr::extract_param_names(constraint) {
 882→                // Sub-path params (e.g. "config.timeout") won't match top-level names
 883→                if !name.contains('.') {
 884→                    debug_assert!(
 885→                        known.contains(name.as_str()),
 886→                        "constraint references unknown param {name:?}, \
 887→                         known params: {known:?}"
 888→                    );
 889→                }
 890→            }
 891→        }
 892→    }
 893→
 894→    let mut cfg = Config::new();
 895→    if let Some(ms) = solver_timeout_ms {
 896→        cfg.set_timeout_msec(ms);
 897→    }
 898→    let param_sorts = build_param_sorts(param_infos);
 899→    z3::with_z3_config(&cfg, || {
 900→        let solver = Solver::new();
 901→        let mut vars = VarTable::new(param_sorts.clone());
 902→
 903→        // Assert the prefix constraints as-is.
 904→        for constraint in &constraints[..negate_index] {
 905→            let sort = infer_operand_sort(constraint);
 906→            let bool_expr = to_z3_bool_constraint(&mut vars, constraint, sort)?;
 907→            solver.assert(&bool_expr);
 908→        }
 909→
 910→        // Negate the target constraint.
 911→        let target = &constraints[negate_index];
 912→        let sort = infer_operand_sort(target);
 913→        let target_bool = to_z3_bool_constraint(&mut vars, target, sort)?;
 914→        solver.assert(target_bool.not());
 915→
 916→        check_and_extract(&solver, &vars)
 917→    })
 918→}
