 962→fn check_and_extract(solver: &Solver, vars: &VarTable) -> Result<SolveResult, SolverError> {
 963→    match solver.check() {
 964→        SatResult::Sat => {
 965→            let model = solver.get_model().ok_or_else(|| {
 966→                SolverError::Unknown("solver returned sat but no model available".into())
 967→            })?;
 968→            let values = extract_concrete_values(&model, vars);
 969→            Ok(SolveResult::Sat(values))
 970→        }
 971→        SatResult::Unsat => Ok(SolveResult::Unsat),
 972→        SatResult::Unknown => Err(SolverError::Unknown(
 973→            solver
 974→                .get_reason_unknown()
 975→                .unwrap_or_else(|| "no reason given".into()),
 976→        )),
 977→    }
 978→}
