771→                let s = val.to_string();
772→                if let Ok(f) = s.parse::<f64>() {
773→                    result.insert(name.clone(), ConcreteValue::Float(f));
774→                }
775→            }
776→        }
777→    }
778→
779→    for (name, ast) in &vars.bools {
780→        if let Some(val) = model.eval(ast, true)
781→            && let Some(b) = val.as_bool()
782→        {
783→            result.insert(name.clone(), ConcreteValue::Bool(b));
784→        }
785→    }
786→
787→    for (name, ast) in &vars.strings {
788→        if let Some(val) = model.eval(ast, true)
789→            && let Some(s) = val.as_string()
790→        {
