827→/// Whether a `ConcreteValue` is compatible with a `TypeInfo`.
828→fn concrete_value_matches_type(value: &ConcreteValue, ty: &TypeInfo) -> bool {
829→    match (value, ty) {
830→        // Numeric types are interchangeable — Z3 may solve a Float param as Int
831→        // when the constraints only use integer comparisons, and vice versa.
832→        (ConcreteValue::Int(_) | ConcreteValue::Float(_), TypeInfo::Int | TypeInfo::Float) => true,
833→        (ConcreteValue::Str(_), TypeInfo::Str) => true,
834→        (ConcreteValue::Bool(_), TypeInfo::Bool) => true,
835→        // Nullable<inner> — the solved value should match the inner type
836→        (_, TypeInfo::Nullable { inner }) => concrete_value_matches_type(value, inner),
837→        // Complex value wraps a repr that Z3 solved — accept any complex match.
838→        (ConcreteValue::Complex { .. }, TypeInfo::Complex { .. }) => true,
839→        // Int is the Z3 default for types it can't represent (arrays, objects, unions,
840→        // unknown, opaque). Accept Int for any non-primitive type.
841→        (ConcreteValue::Int(_), _) => {
842→            !matches!(ty, TypeInfo::Str | TypeInfo::Bool)
843→        }
844→        _ => false,
845→    }
846→}

