860:pub fn solve_for_new_path(

 855→/// Returns `SolveResult::Sat` with concrete variable assignments if satisfiable,
 856→/// or `SolveResult::Unsat` if no inputs can reach the negated path.
 857→#[requires(negate_index < constraints.len(), "negate_index must be within constraints bounds")]
 858→#[contracts::ensures(solved_values_match_param_types(ret.as_ref(), param_infos),
 859→    "solved value types must be compatible with declared ParamInfo types")]
 860→pub fn solve_for_new_path(
 861→    constraints: &[SymExpr],
 862→    negate_index: usize,
 863→    solver_timeout_ms: Option<u64>,
 864→    param_infos: &[ParamInfo],
 865→) -> Result<SolveResult, SolverError> {
 866→    if negate_index >= constraints.len() {
 867→        return Err(SolverError::Unsupported(format!(
 868→            "negate_index {negate_index} out of bounds (len={})",
 869→            constraints.len()
 870→        )));
 871→    }
 872→
 873→    // Debug-only: verify constraint param names exist in param_infos when
 874→    // param_infos is non-empty. Unknown params get default Int sort in Z3,
 875→    // which silently produces wrong solutions for String/Bool params.
 876→    #[cfg(debug_assertions)]
 877→    if !param_infos.is_empty() {
 878→        let known: std::collections::HashSet<&str> =
 879→            param_infos.iter().map(|p| p.name.as_str()).collect();
 880→        for constraint in constraints {
 881→            for name in crate::sym_expr::extract_param_names(constraint) {
 882→                // Sub-path params (e.g. "config.timeout") won't match top-level names
 883→                if !name.contains('.') {
 884→                    debug_assert!(
 885→                        known.contains(name.as_str()),
 886→                        "constraint references unknown param {name:?}, \
 887→                         known params: {known:?}"
 888→                    );
 889→                }
 890→            }
 891→        }
 892→    }
 893→
 894→    let mut cfg = Config::new();
 895→    if let Some(ms) = solver_timeout_ms {
 896→        cfg.set_timeout_msec(ms);
 897→    }
 898→    let param_sorts = build_param_sorts(param_infos);
 899→    z3::with_z3_config(&cfg, || {
 900→        let solver = Solver::new();
 901→        let mut vars = VarTable::new(param_sorts.clone());
 902→
 903→        // Assert the prefix constraints as-is.
 904→        for constraint in &constraints[..negate_index] {
 905→            let sort = infer_operand_sort(constraint);
 906→            let bool_expr = to_z3_bool_constraint(&mut vars, constraint, sort)?;
 907→            solver.assert(&bool_expr);
 908→        }
 909→
 910→        // Negate the target constraint.
 911→        let target = &constraints[negate_index];
 912→        let sort = infer_operand_sort(target);
 913→        let target_bool = to_z3_bool_constraint(&mut vars, target, sort)?;
 914→        solver.assert(target_bool.not());
 915→
 916→        check_and_extract(&solver, &vars)
 917→    })
 918→}
 919→
 920→/// Solve a set of constraints directly (without negation).
 921→///
 922→/// Useful for checking satisfiability of a complete constraint set.
 923→pub fn solve_constraints(
 924→    constraints: &[SymExpr],
 925→    solver_timeout_ms: Option<u64>,
 926→    param_infos: &[ParamInfo],
 927→) -> Result<SolveResult, SolverError> {
 928→    let mut cfg = Config::new();
 929→    if let Some(ms) = solver_timeout_ms {
 930→        cfg.set_timeout_msec(ms);
 931→    }
 932→    let param_sorts = build_param_sorts(param_infos);
 933→    z3::with_z3_config(&cfg, || {
 934→        let solver = Solver::new();
 935→        let mut vars = VarTable::new(param_sorts.clone());
 936→
 937→        for constraint in constraints {
 938→            let sort = infer_operand_sort(constraint);
 939→            let bool_expr = to_z3_bool_constraint(&mut vars, constraint, sort)?;
 940→            solver.assert(&bool_expr);
 941→        }
 942→
 943→        check_and_extract(&solver, &vars)
 944→    })
 945→}
 946→
 947→fn to_z3_bool_constraint(
 948→    vars: &mut VarTable,
 949→    expr: &SymExpr,
 950→    sort: Sort,
 951→) -> Result<Bool, SolverError> {
 952→    let z3_expr = to_z3_expr(vars, expr, sort)?;
 953→    match z3_expr {
 954→        Z3Ast::Bool(b) => Ok(b),
 955→        _ => Err(SolverError::TypeMismatch {
 956→            expected: "Bool".into(),
 957→            actual: "non-Bool constraint".into(),
 958→        }),
 959→    }
 960→}
 961→
 962→fn check_and_extract(solver: &Solver, vars: &VarTable) -> Result<SolveResult, SolverError> {
 963→    match solver.check() {
 964→        SatResult::Sat => {
 965→            let model = solver.get_model().ok_or_else(|| {
 966→                SolverError::Unknown("solver returned sat but no model available".into())
 967→            })?;
 968→            let values = extract_concrete_values(&model, vars);
 969→            Ok(SolveResult::Sat(values))
 970→        }
 971→        SatResult::Unsat => Ok(SolveResult::Unsat),
 972→        SatResult::Unknown => Err(SolverError::Unknown(
 973→            solver
 974→                .get_reason_unknown()
 975→                .unwrap_or_else(|| "no reason given".into()),
 976→        )),
 977→    }
 978→}
