 66→    ///
 67→    /// Returns `Some(n)` for exhaustible strategies (boundary seeds, literals,
 68→    /// pool, user-provided) and `None` for infinite strategies (random, fuzzer,
 69→    /// Z3 solver).
 70→    fn estimated_size(&self) -> Option<u64> {
 71→        None
 72→    }
