    let mut result = make_exec_result();
    result.branch_path = vec![BranchDecision {
        branch_id: 1,
        taken: true,
        location: None,
        constraint: SymConstraint::Unknown { hint: "opaque".into() },
        branch_type: None,
    }];

    s.feedback(&[Value::from(0)], &result, false);
    assert!(s.next(&ctx).is_none());
}
```

#### Step 5: Property-based tests

Add to the `prop_tests` module inside the `#[cfg(test)]` block of strategy.rs:

**Property 1: feedback never panics on arbitrary ExecuteResults.**
