#[test]
fn z3_solver_output_preserves_input_length(
    er in arb_execute_result(),
    len in 1..5usize,
) {
    let inputs: Vec<Value> = (0..len).map(|i| Value::from(i as i64)).collect();
    let params: Vec<ParamInfo> = (0..len)
        .map(|i| ParamInfo {
            name: format!("p{i}"),
