**Property 3: multiple feedback calls accumulate in pending.**
```rust
#[test]
fn z3_solver_multiple_feedbacks_accumulate(
    er1 in arb_execute_result(),
    er2 in arb_execute_result(),
) {
    let params = vec![ParamInfo {
        name: "x".into(),
        typ: TypeInfo::Int,
        type_name: None,
    }];
    let mut s = Z3SolverStrategy::new(Some(500), params);
    let inputs = vec![Value::from(0)];
    s.feedback(&inputs, &er1, false);
    let count_after_first = std::iter::from_fn(|| {
        let ctx = StrategyContext {
            params: vec![ParamInfo { name: "x".into(), typ: TypeInfo::Int, type_name: None }],
            literals: vec![],
            capabilities: FrontendCapabilities::from_raw(&[]),
        };
        s.next(&ctx)
    }).count();
    // Re-feed
    s.feedback(&inputs, &er2, true);
    // Should not panic, and count >= 0 (we can't predict solvability).
    prop_assert!(count_after_first >= 0); // trivially true, but exercises the path
}
