    /// Max iterations budget stops exploration.
    #[tokio::test]
    async fn explore_stops_on_max_iterations() {
        let config = config_for_script("concolic-test-frontend.sh");
        let mut frontend = Frontend::spawn(&config).await.expect("spawn failed");

