        let a = FixedStrategy::new("a", vec![vec![Value::from(1)], vec![Value::from(2)]]);
        let b = FixedStrategy::new("b", vec![vec![Value::from(10)], vec![Value::from(20)]]);
        let config = MetaConfig {
